  1→package connector
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→
  9→	"golang.org/x/oauth2"
 10→	"golang.org/x/oauth2/google"
 11→)
 12→
 13→func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 14→	var oauthCfg *oauth2.Config
 15→	var authOpts []oauth2.AuthCodeOption
 16→
 17→	if g.def.Credentials.Source == "google_json" {
 18→		// Google-specific: use google.ConfigFromJSON
 19→		credsData, err := g.loadGoogleCredentials()
 20→		if err != nil {
 21→			return nil, err
 22→		}
 23→		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 24→		if err != nil {
 25→			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 26→		}
 27→		oauthCfg = cfg
 28→	} else {
 29→		// Generic OAuth2: build config from YAML
 30→		clientID, clientSecret, err := g.resolveOAuthCredentials()
 31→		if err != nil {
 32→			return nil, err
 33→		}
 34→		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 35→		if err != nil {
 36→			return nil, err
 37→		}
 38→		oauthCfg = cfg
 39→		authOpts = opts
 40→	}
 41→
 42→	// Add extra_params as auth options for google_json too
 43→	if g.def.Credentials.Source == "google_json" {
 44→		for k, v := range g.def.Auth.ExtraParams {
 45→			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 46→		}
 47→	}
 48→
 49→	// Run shared OAuth flow
 50→	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 51→	if err != nil {
 52→		return nil, err
 53→	}
 54→
 55→	// Save token
 56→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 57→	tokenPath := tokenDir + "/token.json"
 58→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 59→		return nil, fmt.Errorf("creating connector dir: %w", err)
 60→	}
 61→	if err := saveToken(tokenPath, token); err != nil {
 62→		return nil, fmt.Errorf("saving token: %w", err)
 63→	}
 64→
 65→	// Save granted scopes for later scope-sufficiency checks
 66→	if len(g.def.Auth.Scopes) > 0 {
 67→		_ = SaveGrantedScopes(tokenDir, g.def.Auth.Scopes)
 68→	}
 69→
 70→	// Verify connection + get account identifier
 71→	account, err := g.runVerify(ctx, oauthCfg, token)
 72→	if err != nil {
 73→		// Non-fatal: connected but can't verify
 74→		account = "connected (unverified)"
 75→	}
 76→
 77→	return &Result{
 78→		Account: account,
 79→		Token:   token,
 80→	}, nil
 81→}
 82→
 83→func (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
 84→	key := os.Getenv(g.def.Auth.EnvVar)
 85→	if key == "" {
 86→		// Check if stdin is a TTY for prompt
 87→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
 88→			fmt.Printf("Enter your %s API key: ", g.def.Name)
 89→			fmt.Scanln(&key)
 90→		}
 91→		if key == "" {
 92→			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
 93→		}
 94→	}
 95→
 96→	// Save API key
 97→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 98→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 99→		return nil, fmt.Errorf("creating connector dir: %w", err)
100→	}
101→	credsPath := tokenDir + "/credentials.json"
102→	credsData, _ := json.Marshal(map[string]string{"api_key": key})
103→	if err := os.WriteFile(credsPath, credsData, 0600); err != nil {
104→		return nil, fmt.Errorf("saving credentials: %w", err)
105→	}
106→
107→	// Verify
108→	account, err := g.runVerifyAPIKey(ctx, key)
109→	if err != nil {
110→		account = "connected (unverified)"
111→	}
112→
113→	return &Result{
114→		Account: account,
115→		Meta:    map[string]string{"api_key": key},
116→	}, nil
117→}
118→
119→func (g *GenericConnector) connectBasic(ctx context.Context) (*Result, error) {
120→	username := os.Getenv(g.def.Auth.UsernameVar)
121→	password := os.Getenv(g.def.Auth.PasswordVar)
122→	if username == "" || password == "" {
123→		return nil, fmt.Errorf("%s credentials not found. Set %s and %s environment variables",
124→			g.def.Name, g.def.Auth.UsernameVar, g.def.Auth.PasswordVar)
125→	}
126→
127→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
128→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
129→		return nil, fmt.Errorf("creating connector dir: %w", err)
130→	}
131→	credsData, _ := json.Marshal(map[string]string{"username": username, "password": password})
132→	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
133→		return nil, fmt.Errorf("saving credentials: %w", err)
134→	}
135→
136→	return &Result{Account: username}, nil
137→}
138→
139→func (g *GenericConnector) connectWebhook(ctx context.Context) (*Result, error) {
140→	webhookURL := os.Getenv(g.def.Auth.URLVar)
141→	if webhookURL == "" {
142→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
143→			fmt.Printf("Enter your %s webhook URL: ", g.def.Name)
144→			fmt.Scanln(&webhookURL)
145→		}
146→		if webhookURL == "" {
147→			return nil, fmt.Errorf("%s webhook URL not found. Set %s environment variable",
148→				g.def.Name, g.def.Auth.URLVar)
149→		}
150→	}
151→
152→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
153→	if err := os.MkdirAll(tokenDir, 0700); err != nil {
154→		return nil, fmt.Errorf("creating connector dir: %w", err)
155→	}
156→	credsData, _ := json.Marshal(map[string]string{"webhook_url": webhookURL})
157→	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
158→		return nil, fmt.Errorf("saving credentials: %w", err)
159→	}
160→
161→	return &Result{Account: webhookURL}, nil
162→}
