  1→package connector
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→// HealthStatus represents the outcome of a connector health check.
 11→type HealthStatus int
 12→
 13→const (
 14→	HealthOK           HealthStatus = iota
 15→	HealthTokenMissing              // config says connected but no auth files on disk
 16→	HealthTokenCorrupt              // auth file exists but contains invalid JSON
 17→	HealthOrphanedToken             // config says disconnected but auth files remain
 18→)
 19→
 20→func (h HealthStatus) String() string {
 21→	switch h {
 22→	case HealthOK:
 23→		return "ok"
 24→	case HealthTokenMissing:
 25→		return "token_missing"
 26→	case HealthTokenCorrupt:
 27→		return "token_corrupt"
 28→	case HealthOrphanedToken:
 29→		return "orphaned_token"
 30→	default:
 31→		return "unknown"
 32→	}
 33→}
 34→
 35→// HealthResult holds the outcome of CheckHealth for a single connector.
 36→type HealthResult struct {
 37→	ConnectorID string
 38→	Status      HealthStatus
 39→	Message     string
 40→}
 41→
 42→// CheckHealth verifies consistency between a connector's config state
 43→// (connected or not) and its on-disk auth files (token.json / credentials.json).
 44→// When convexBacked is true, missing local auth files are expected (auth is server-managed).
 45→func CheckHealth(connectorID, connectorDir string, configConnected bool, convexBacked bool) HealthResult {
 46→	tokenPath := filepath.Join(connectorDir, "token.json")
 47→	credsPath := filepath.Join(connectorDir, "credentials.json")
 48→
 49→	hasToken := fileExists(tokenPath)
 50→	hasCreds := fileExists(credsPath)
 51→	hasAnyAuth := hasToken || hasCreds
 52→
 53→	if configConnected {
 54→		if convexBacked {
 55→			// Convex-backed connectors don't need local auth files.
 56→			// Validate any files that do exist, but absence is normal.
 57→			if hasToken {
 58→				if err := validateJSON(tokenPath); err != nil {
 59→					return HealthResult{ConnectorID: connectorID, Status: HealthTokenCorrupt, Message: fmt.Sprintf("token.json is corrupt: %v", err)}
 60→				}
 61→			}
 62→			return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy (server-managed)"}
 63→		}
 64→		if !hasAnyAuth {
 65→			return HealthResult{
 66→				ConnectorID: connectorID,
 67→				Status:      HealthTokenMissing,
 68→				Message:     fmt.Sprintf("config says connected but no token/credentials found in %s", connectorDir),
 69→			}
 70→		}
 71→		if hasToken {
 72→			if err := validateJSON(tokenPath); err != nil {
 73→				return HealthResult{
 74→					ConnectorID: connectorID,
 75→					Status:      HealthTokenCorrupt,
 76→					Message:     fmt.Sprintf("token.json is corrupt: %v", err),
 77→				}
 78→			}
 79→		}
 80→		if hasCreds && !hasToken {
 81→			if err := validateJSON(credsPath); err != nil {
 82→				return HealthResult{
 83→					ConnectorID: connectorID,
 84→					Status:      HealthTokenCorrupt,
 85→					Message:     fmt.Sprintf("credentials.json is corrupt: %v", err),
 86→				}
 87→			}
 88→		}
 89→		return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy"}
 90→	}
 91→
 92→	// Not connected according to config.
 93→	if hasAnyAuth {
 94→		return HealthResult{
 95→			ConnectorID: connectorID,
 96→			Status:      HealthOrphanedToken,
 97→			Message:     fmt.Sprintf("config says disconnected but auth files exist in %s", connectorDir),
 98→		}
 99→	}
100→	return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "clean"}
101→}
102→
103→// SaveGrantedScopes writes the granted OAuth scopes to scopes.json in the connector directory.
104→func SaveGrantedScopes(connectorDir string, scopes []string) error {
105→	data, err := json.Marshal(scopes)
106→	if err != nil {
107→		return err
108→	}
109→	return os.WriteFile(filepath.Join(connectorDir, "scopes.json"), data, 0600)
110→}
111→
112→// LoadGrantedScopes reads the granted OAuth scopes from scopes.json.
113→// Returns nil, nil if the file does not exist (graceful for old tokens).
114→func LoadGrantedScopes(connectorDir string) ([]string, error) {
115→	data, err := os.ReadFile(filepath.Join(connectorDir, "scopes.json"))
116→	if err != nil {
117→		if os.IsNotExist(err) {
118→			return nil, nil
119→		}
120→		return nil, err
121→	}
122→	var scopes []string
123→	return scopes, json.Unmarshal(data, &scopes)
124→}
125→
126→// CheckScopesSufficient returns true if all required scopes are present in granted.
127→func CheckScopesSufficient(granted, required []string) bool {
128→	set := make(map[string]bool, len(granted))
129→	for _, s := range granted {
130→		set[s] = true
131→	}
132→	for _, s := range required {
133→		if !set[s] {
134→			return false
135→		}
136→	}
137→	return true
138→}
139→
140→func fileExists(path string) bool {
141→	_, err := os.Stat(path)
142→	return err == nil
143→}
144→
145→func validateJSON(path string) error {
146→	data, err := os.ReadFile(path)
147→	if err != nil {
148→		return err
149→	}
150→	var v interface{}
151→	return json.Unmarshal(data, &v)
152→}
