 56→var connectCmd = &cobra.Command{
 57→	Use:   "connect <service>",
 58→	Short: "Connect a service (gmail, linkedin)",
 59→	Args:  cobra.ExactArgs(1),
 60→	RunE: func(cmd *cobra.Command, args []string) error {
 61→		id := args[0]
 62→		if connected, account := checkExistingConnection(id); connected {
 63→			if !forceConnect {
 64→				fmt.Fprintf(os.Stderr, "  %s is already connected (%s)\n  Use --force to reconnect\n", id, account)
 65→				return fmt.Errorf("%s already connected, use --force to overwrite", id)
 66→			}
 67→			// Clean up old connection state before reconnecting
 68→			fmt.Fprintf(os.Stderr, "  Replacing existing %s connection (%s)...\n", id, account)
 69→			tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
 70→			_ = os.RemoveAll(tokenDir)
 71→		}
 72→		cleanup, err := acquireConnectLock(id)
 73→		if err != nil {
 74→			return err
 75→		}
 76→		defer cleanup()
 77→		switch id {
 78→		case "gmail":
 79→			return connectGmail()
 80→		case "linkedin":
 81→			return connectLinkedIn()
 82→		default:
 83→			registry, err := connector.LoadRegistry(projectLocalDefs)
 84→			if err != nil {
 85→				return fmt.Errorf("loading connector registry: %w", err)
 86→			}
 87→			var found *connector.ConnectorDef
 88→			for i := range registry {
 89→				if registry[i].ID == id {
 90→					found = &registry[i]
 91→					break
 92→				}
 93→			}
 94→			if found == nil {
 95→				return fmt.Errorf("unknown connector: %s\n  Run `nurge connectors available` to see all connectors", id)
 96→			}
 97→			c := connector.NewFromDef(*found, "")
 98→			result, err := c.Connect(cmd.Context())
 99→			if err != nil {
100→				return fmt.Errorf("connecting %s: %w", id, err)
101→			}
102→			if project.IsNurgeProject(".") {
103→				_ = project.SetConnector(id, found.Type, result.Account)
104→			}
105→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m %s connected (%s)\n", found.Name, result.Account)
106→		}
107→		return nil
108→	},
109→}
