16→	Short: "Disconnect a service (gmail, hubspot)",
17→	Args:  cobra.ExactArgs(1),
18→	RunE: func(cmd *cobra.Command, args []string) error {
19→		id := args[0]
20→
21→		cfg, err := project.Load()
22→		if err != nil {
23→			return fmt.Errorf("loading config: %w", err)
24→		}
25→
26→		cs, ok := cfg.Connectors[id]
27→		if !ok || !cs.Connected {
28→			return fmt.Errorf("%s is not connected", id)
29→		}
30→
31→		// 1. Update config first (source of truth)
32→		if err := project.RemoveConnector(id); err != nil {
33→			return fmt.Errorf("updating config: %w", err)
34→		}
35→
36→		// 1.5. Reset sync cursor in DB so reconnect gets fresh sync (best effort)
37→		if d, dbErr := db.Open(); dbErr == nil {
38→			defer d.Close()
39→			d.Exec("DELETE FROM connectors WHERE id = ? OR id = ?", id, id+"-convex")
40→		}
41→
42→		// 2. Notify server for Convex-backed connectors (best effort)
43→		if id == "gmail" || id == "linkedin" {
44→			af, err := account.LoadAuth()
45→			if err == nil && af.Token != "" {
46→				client := account.NewConvexClient(cmdutil.GetConvexURL())
47→				providerMap := map[string]string{"gmail": "GOOGLE", "linkedin": "LINKEDIN"}
48→				if err := client.DisconnectProvider(af.Token, providerMap[id]); err != nil {
49→					fmt.Fprintf(os.Stderr, "  warning: could not notify server: %v\n", err)
50→				}
51→			}
52→		}
53→
54→		// 3. Delete token files (best effort, config already updated)
55→		tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
56→		if err := os.RemoveAll(tokenDir); err != nil {
57→			fmt.Fprintf(os.Stderr, "  warning: could not remove %s: %v\n", tokenDir, err)
58→		}
59→
60→		fmt.Printf("\033[32m✓\033[0m %s disconnected\n", id)
61→		return nil
62→	},
