36→
37→	gc := &GenericConnector{def: def}
38→	cfg, opts, err := gc.buildOAuthConfig("test-client-id", "test-secret")
39→	if err != nil {
40→		t.Fatalf("buildOAuthConfig: %v", err)
41→	}
42→	if cfg.ClientID != "test-client-id" {
43→		t.Errorf("ClientID = %q, want test-client-id", cfg.ClientID)
44→	}
