  1→package project
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→type hooksStep struct{}
 11→
 12→func (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13→
 14→// hookEntry is a single hook within a matcher group.
 15→// Exactly one of command or prompt must be set.
 16→type hookEntry struct {
 17→	command string // for type "command"
 18→	prompt  string // for type "prompt"
 19→}
 20→
 21→// hookGroup defines a matcher group with its hooks for a given event.
 22→type hookGroup struct {
 23→	event   string
 24→	matcher string
 25→	hooks   []hookEntry
 26→}
 27→
 28→// requiredHookGroups defines all hook groups nurge needs installed.
 29→// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
 30→var requiredHookGroups = []hookGroup{
 31→	{
 32→		event:   "PostToolUse",
 33→		matcher: "Bash",
 34→		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
 35→	},
 36→	{
 37→		event:   "SessionStart",
 38→		matcher: "",
 39→		hooks:   []hookEntry{{command: "nurge hook session-start"}},
 40→	},
 41→	{
 42→		event:   "UserPromptSubmit",
 43→		matcher: "",
 44→		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
 45→	},
 46→	{
 47→		event:   "Stop",
 48→		matcher: "",
 49→		hooks: []hookEntry{
 50→			{command: "nurge hook stop"},
 51→			{prompt: "Before finishing, capture any new insights from this session. If you learned something about tone preferences, ICP refinements, product positioning, messaging patterns, competitor intel, or user preferences, save each as: nurge learn save --type <type> (types: tone, icp, product, pattern, preference, competitor). Only save non-obvious insights that will help future sessions. Skip if nothing new was learned. Keep each learning to 1-2 sentences."},
 52→		},
 53→	},
 54→	{
 55→		event:   "SessionEnd",
 56→		matcher: "",
 57→		hooks:   []hookEntry{{command: "nurge hook session-end"}},
 58→	},
 59→}
 60→
 61→func (s *hooksStep) Done() (bool, error) {
 62→	data, err := os.ReadFile(claudeSettingsPath())
 63→	if err != nil {
 64→		if os.IsNotExist(err) {
 65→			return false, nil
 66→		}
 67→		return false, err
 68→	}
 69→
 70→	var settings map[string]any
 71→	if err := json.Unmarshal(data, &settings); err != nil {
 72→		return false, nil
 73→	}
 74→
 75→	hooks, ok := settings["hooks"].(map[string]any)
 76→	if !ok {
 77→		return false, nil
 78→	}
 79→
 80→	for _, g := range requiredHookGroups {
 81→		for _, h := range g.hooks {
 82→			if !hookEntryExists(hooks, g.event, h) {
 83→				return false, nil
 84→			}
 85→		}
 86→	}
 87→	return true, nil
 88→}
 89→
 90→func (s *hooksStep) Run() error {
 91→	settingsPath := claudeSettingsPath()
 92→
 93→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 94→		return fmt.Errorf("creating .claude/: %w", err)
 95→	}
 96→
 97→	// Load existing settings or start fresh
 98→	settings := make(map[string]any)
 99→	if data, err := os.ReadFile(settingsPath); err == nil {
100→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
101→	}
102→
103→	hooks, _ := settings["hooks"].(map[string]any)
104→	if hooks == nil {
105→		hooks = make(map[string]any)
106→	}
107→
108→	for _, g := range requiredHookGroups {
109→		// Collect entries that are missing
110→		var missing []hookEntry
111→		for _, h := range g.hooks {
112→			if !hookEntryExists(hooks, g.event, h) {
113→				missing = append(missing, h)
114→			}
115→		}
116→		if len(missing) == 0 {
117→			continue
118→		}
119→
120→		// Find existing matcher entry for this event+matcher, or create one
121→		eventHooks, _ := hooks[g.event].([]any)
122→		matcherIdx := -1
123→		for i, item := range eventHooks {
124→			m, ok := item.(map[string]any)
125→			if !ok {
126→				continue
127→			}
128→			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
129→				matcherIdx = i
130→				break
131→			}
132→		}
133→
134→		if matcherIdx >= 0 {
135→			entry := eventHooks[matcherIdx].(map[string]any)
136→			innerHooks, _ := entry["hooks"].([]any)
137→			for _, h := range missing {
138→				innerHooks = append(innerHooks, hookEntryToJSON(h))
139→			}
140→			entry["hooks"] = innerHooks
141→		} else {
142→			var innerHooks []any
143→			for _, h := range g.hooks {
144→				innerHooks = append(innerHooks, hookEntryToJSON(h))
145→			}
146→			entry := map[string]any{
147→				"matcher": g.matcher,
148→				"hooks":   innerHooks,
149→			}
150→			eventHooks = append(eventHooks, entry)
151→		}
152→		hooks[g.event] = eventHooks
153→	}
154→
155→	settings["hooks"] = hooks
156→
157→	// Sync permissions into the settings
158→	syncPermissionsInto(settings)
159→
160→	data, err := json.MarshalIndent(settings, "", "  ")
161→	if err != nil {
162→		return fmt.Errorf("marshaling settings: %w", err)
163→	}
164→
165→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
166→		return fmt.Errorf("writing settings: %w", err)
167→	}
168→
169→	return nil
170→}
171→
172→// hookEntryExists checks if a specific hook entry (command or prompt) already
173→// exists under the given event key.
174→func hookEntryExists(hooks map[string]any, event string, entry hookEntry) bool {
175→	arr, ok := hooks[event].([]any)
176→	if !ok {
177→		return false
178→	}
179→	for _, item := range arr {
180→		m, ok := item.(map[string]any)
181→		if !ok {
182→			continue
183→		}
184→		innerHooks, ok := m["hooks"].([]any)
185→		if !ok {
186→			continue
187→		}
188→		for _, h := range innerHooks {
189→			hm, ok := h.(map[string]any)
190→			if !ok {
191→				continue
192→			}
193→			if entry.command != "" {
194→				if cmd, ok := hm["command"].(string); ok && cmd == entry.command {
195→					return true
196→				}
197→			}
198→			if entry.prompt != "" {
199→				if p, ok := hm["prompt"].(string); ok && p == entry.prompt {
200→					return true
201→				}
202→			}
203→		}
204→	}
205→	return false
206→}
