222→func hookEntryToJSON(entry hookEntry) map[string]any {
223→	if entry.prompt != "" {
224→		return map[string]any{"type": "prompt", "prompt": entry.prompt}
225→	}
226→	return map[string]any{"type": "command", "command": entry.command}
