166→// extractContent tries to pretty-print JSON content; falls back to raw string.
167→func extractContent(raw json.RawMessage) string {
168→	// Try to unmarshal as a string first (common for text atoms)
169→	var s string
170→	if err := json.Unmarshal(raw, &s); err == nil {
171→		return s
172→	}
173→	// Return formatted JSON for structured atoms
174→	var pretty json.RawMessage
175→	if err := json.Unmarshal(raw, &pretty); err == nil {
176→		indented, err := json.MarshalIndent(pretty, "", "  ")
177→		if err == nil {
178→			return string(indented)
179→		}
180→	}
181→	return string(raw)
182→}
