195→// taskLearningTypes maps task types to relevant learning types.
196→func taskLearningTypes(task TaskType) []string {
197→	switch task {
198→	case TaskOutbound, TaskSequence, TaskBook:
199→		return []string{"tone", "style", "positioning", "rejection", "preference"}
200→	case TaskFollowup:
201→		return []string{"tone", "style", "timing", "preference"}
202→	case TaskReply:
203→		return []string{"tone", "objection", "style", "preference"}
204→	case TaskResearch, TaskQualify:
205→		return []string{"icp", "positioning", "preference"}
206→	case TaskPipeline:
207→		return []string{"preference", "workflow"}
208→	case TaskAnalytics, TaskReview:
209→		return []string{"preference", "metric"}
210→	case TaskProspects, TaskICP, TaskPersonas:
211→		return []string{"icp", "persona", "preference"}
212→	case TaskProduct:
213→		return []string{"positioning", "product", "preference"}
214→	case TaskHygiene, TaskSendHealth:
215→		return []string{"preference", "compliance"}
216→	default:
217→		return nil
218→	}
219→}
220→
221→// queryLearningsByTypes fetches learnings, optionally filtered by type, newest first.
222→func queryLearningsByTypes(database *sql.DB, types []string, limit int) ([]Learning, error) {
223→	var query string
224→	var args []any
225→
226→	if len(types) == 0 {
227→		query = `SELECT id, type, content, source_session, created_at FROM learnings ORDER BY created_at DESC LIMIT ?`
228→		args = append(args, limit)
229→	} else {
230→		placeholders := make([]string, len(types))
231→		for i, t := range types {
232→			placeholders[i] = "?"
233→			args = append(args, t)
234→		}
235→		query = fmt.Sprintf(
236→			`SELECT id, type, content, source_session, created_at FROM learnings WHERE type IN (%s) ORDER BY created_at DESC LIMIT ?`,
237→			strings.Join(placeholders, ","),
238→		)
239→		args = append(args, limit)
240→	}
241→
242→	rows, err := database.Query(query, args...)
243→	if err != nil {
244→		return nil, fmt.Errorf("querying learnings: %w", err)
245→	}
246→	defer rows.Close()
247→
248→	var learnings []Learning
249→	for rows.Next() {
250→		var l Learning
251→		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
252→			return nil, fmt.Errorf("scanning learning: %w", err)
253→		}
254→		learnings = append(learnings, l)
255→	}
256→	return learnings, rows.Err()
257→}
