169→func connectLinkedIn() error {
170→	af, err := account.LoadAuth()
171→	if err != nil || af.Token == "" {
172→		return fmt.Errorf("not logged in. Run: nurge account login")
173→	}
174→
175→	client := account.NewConvexClient(cmdutil.GetConvexURL())
176→
177→	fmt.Fprintf(os.Stderr, "  Requesting LinkedIn connection...\n")
178→	resp, err := client.ConnectLinkedIn(af.Token)
179→	if err != nil {
180→		return fmt.Errorf("connect failed: %w", err)
181→	}
182→
183→	if resp.AlreadyConnected {
184→		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m LinkedIn already connected (%s)\n", resp.Name)
185→		if project.IsNurgeProject(".") {
186→			_ = project.SetConnector("linkedin", "social", resp.Name)
187→		}
188→		return nil
189→	}
190→
191→	fmt.Fprintf(os.Stderr, "  Opening browser to connect LinkedIn...\n")
192→	if err := util.OpenBrowser(resp.URL); err != nil {
193→		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
194→	}
195→
196→	fmt.Fprintf(os.Stderr, "  Waiting for LinkedIn connection...")
197→	timeout := time.After(5 * time.Minute)
198→	ticker := time.NewTicker(2 * time.Second)
199→	defer ticker.Stop()
200→
201→	for {
202→		select {
203→		case <-timeout:
204→			fmt.Fprintf(os.Stderr, "\n")
205→			return fmt.Errorf("timed out after 5 minutes waiting for LinkedIn connection.\n  Run `nurge connect linkedin` to try again")
206→		case <-ticker.C:
207→			status, err := client.ConnectionStatus(af.Token, "LINKEDIN")
208→			if err != nil {
209→				continue
210→			}
211→			if status.Connected {
212→				fmt.Fprintf(os.Stderr, "\n  \033[32m✓\033[0m LinkedIn connected (%s)\n", status.Name)
213→				if project.IsNurgeProject(".") {
214→					_ = project.SetConnector("linkedin", "social", status.Name)
215→				}
216→				return nil
217→			}
218→			fmt.Fprintf(os.Stderr, ".")
219→		}
220→	}
221→}
