107→	// Verify
108→	account, err := g.runVerifyAPIKey(ctx, key)
109→	if err != nil {
110→		account = "connected (unverified)"
111→	}
112→
113→	return &Result{
114→		Account: account,
115→		Meta:    map[string]string{"api_key": key},
116→	}, nil
117→}
