  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"io"
  8→	"net/http"
  9→	"os"
 10→	"strings"
 11→
 12→	"golang.org/x/oauth2"
 13→)
 14→
 15→// runVerify calls the verify endpoint using the oauth2 token source (handles refresh).
 16→func (g *GenericConnector) runVerify(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
 17→	if g.def.Verify.URL == "" {
 18→		return "connected", nil
 19→	}
 20→
 21→	// Refresh token first so URL substitution uses a valid access token
 22→	ts := cfg.TokenSource(ctx, token)
 23→	freshToken, err := ts.Token()
 24→	if err != nil {
 25→		fmt.Fprintf(os.Stderr, "  warning: token refresh failed for %s: %v\n  Run `nurge connect %s` if operations fail\n", g.def.ID, err, g.def.ID)
 26→		freshToken = token // fall back to original if refresh fails
 27→	}
 28→	if freshToken.AccessToken == "" {
 29→		return "", fmt.Errorf("no valid access token: refresh failed (%v) and original token has empty access token", err)
 30→	}
 31→	client := oauth2.NewClient(ctx, ts)
 32→	url := strings.ReplaceAll(g.def.Verify.URL, "{{access_token}}", freshToken.AccessToken)
 33→
 34→	method := g.def.Verify.Method
 35→	if method == "" {
 36→		method = "GET"
 37→	}
 38→
 39→	req, err := http.NewRequestWithContext(ctx, method, url, nil)
 40→	if err != nil {
 41→		return "", err
 42→	}
 43→	for k, v := range g.def.Verify.Headers {
 44→		v = strings.ReplaceAll(v, "{{access_token}}", freshToken.AccessToken)
 45→		req.Header.Set(k, v)
 46→	}
 47→
 48→	resp, err := client.Do(req)
 49→	if err != nil {
 50→		return "", err
 51→	}
 52→	defer resp.Body.Close()
 53→
 54→	if resp.StatusCode != 200 {
 55→		body, _ := io.ReadAll(resp.Body)
 56→		return "", ClassifyHTTPError(g.def.ID, resp.StatusCode, string(body))
 57→	}
 58→
 59→	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
 60→}
 61→
 62→// runVerifyAPIKey calls verify with an API key in the configured header.
 63→func (g *GenericConnector) runVerifyAPIKey(ctx context.Context, key string) (string, error) {
 64→	if g.def.Verify.URL == "" {
 65→		return "connected", nil
 66→	}
 67→
 68→	url := strings.ReplaceAll(g.def.Verify.URL, "{{api_key}}", key)
 69→	method := g.def.Verify.Method
 70→	if method == "" {
 71→		method = "GET"
 72→	}
 73→
 74→	req, err := http.NewRequestWithContext(ctx, method, url, nil)
 75→	if err != nil {
 76→		return "", err
 77→	}
 78→
 79→	if g.def.Auth.Header != "" {
 80→		req.Header.Set(g.def.Auth.Header, key)
 81→	}
 82→
 83→	resp, err := http.DefaultClient.Do(req)
 84→	if err != nil {
 85→		return "", err
 86→	}
 87→	defer resp.Body.Close()
 88→
 89→	if resp.StatusCode != 200 {
 90→		body, _ := io.ReadAll(resp.Body)
 91→		return "", ClassifyHTTPError(g.def.ID, resp.StatusCode, string(body))
 92→	}
 93→
 94→	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
 95→}
 96→
 97→// extractAccountField reads the JSON response and tries fields in preference order.
 98→func extractAccountField(body io.Reader, fields []string) (string, error) {
 99→	if len(fields) == 0 {
100→		return "connected", nil
101→	}
102→
103→	var data map[string]interface{}
104→	if err := json.NewDecoder(body).Decode(&data); err != nil {
105→		return "", fmt.Errorf("parsing verify response: %w", err)
106→	}
107→
108→	for _, field := range fields {
109→		if v, ok := data[field]; ok && v != nil {
110→			return fmt.Sprintf("%v", v), nil
111→		}
112→	}
113→
114→	return "connected", nil
115→}
