 1→package connector
 2→
 3→import (
 4→	"errors"
 5→	"fmt"
 6→	"strings"
 7→)
 8→
 9→// AuthError wraps a connector authentication failure with actionable context.
10→type AuthError struct {
11→	ConnectorID string
12→	Reason      string
13→	Err         error
14→}
15→
16→func (e *AuthError) Error() string { return fmt.Sprintf("connector %s: %s", e.ConnectorID, e.Reason) }
17→func (e *AuthError) Unwrap() error { return e.Err }
18→func (e *AuthError) Suggestion() string {
19→	return fmt.Sprintf("run `nurge connect %s` to reconnect", e.ConnectorID)
20→}
21→
22→var (
23→	ErrAuthExpired   = fmt.Errorf("authentication expired")
24→	ErrTokenRevoked  = fmt.Errorf("token revoked by provider")
25→	ErrScopeMismatch = fmt.Errorf("insufficient scopes")
26→)
27→
28→// IsAuthError reports whether err or any error in its chain is an *AuthError.
29→func IsAuthError(err error) bool {
30→	var ae *AuthError
31→	return errors.As(err, &ae)
32→}
33→
34→// NewAuthExpiredError creates an AuthError for expired credentials.
35→func NewAuthExpiredError(connectorID string, cause error) error {
36→	return &AuthError{
37→		ConnectorID: connectorID,
38→		Reason:      "authentication expired",
39→		Err:         fmt.Errorf("%w: %w", ErrAuthExpired, cause),
40→	}
41→}
42→
43→// NewTokenRevokedError creates an AuthError for revoked tokens.
44→func NewTokenRevokedError(connectorID string, cause error) error {
45→	return &AuthError{
46→		ConnectorID: connectorID,
47→		Reason:      "token revoked by provider",
48→		Err:         fmt.Errorf("%w: %w", ErrTokenRevoked, cause),
49→	}
50→}
51→
52→// NewScopeMismatchError creates an AuthError for insufficient OAuth scopes.
53→func NewScopeMismatchError(connectorID string, needed, granted []string) error {
54→	return &AuthError{
55→		ConnectorID: connectorID,
56→		Reason:      fmt.Sprintf("need scopes %v, have %v", needed, granted),
57→		Err:         ErrScopeMismatch,
58→	}
59→}
60→
61→// ClassifyHTTPError turns an HTTP status code and response body into a typed
62→// error. Auth-related codes (401, 403) produce an *AuthError; everything else
63→// returns a plain error.
64→func ClassifyHTTPError(connectorID string, statusCode int, body string) error {
65→	switch {
66→	case statusCode == 401:
67→		return NewAuthExpiredError(connectorID, fmt.Errorf("HTTP %d", statusCode))
68→	case statusCode == 403:
69→		if strings.Contains(strings.ToLower(body), "revoked") {
70→			return NewTokenRevokedError(connectorID, fmt.Errorf("HTTP %d: %s", statusCode, body))
71→		}
72→		return NewAuthExpiredError(connectorID, fmt.Errorf("HTTP %d: %s", statusCode, body))
73→	default:
74→		return fmt.Errorf("HTTP %d: %s", statusCode, body)
75→	}
76→}
