 13→
 14→// Enrich enriches a single contact, filling missing fields via the waterfall.
 15→func Enrich(db *sql.DB, req EnrichRequest) (*EnrichResult, error) {
 16→	if req.ContactEmail == "" {
 17→		return nil, fmt.Errorf("contact email is required")
 18→	}
 19→
 20→	// Load provider registry
 21→	registry, err := LoadProviders()
 22→	if err != nil {
 23→		return nil, fmt.Errorf("loading providers: %w", err)
 24→	}
 25→
 26→	// Load contact from DB
 27→	contact, err := loadContact(db, req.ContactEmail)
 28→	if err != nil {
 29→		return nil, fmt.Errorf("loading contact %s: %w", req.ContactEmail, err)
 30→	}
 31→
 32→	// Determine which fields need enrichment
 33→	currentValues := contact.fieldMap()
 34→	var targetFields []string
 35→	if len(req.Fields) > 0 {
 36→		targetFields = req.Fields
 37→	} else {
 38→		targetFields = AllEnrichableFields()
 39→	}
 40→
 41→	var missingFields []string
 42→	for _, f := range targetFields {
 43→		if val, ok := currentValues[f]; !ok || val == "" {
 44→			missingFields = append(missingFields, f)
 45→		}
 46→	}
 47→
 48→	result := &EnrichResult{
 49→		ContactEmail: req.ContactEmail,
 50→		FieldsFilled: make(map[string]string),
 51→	}
 52→
 53→	if len(missingFields) == 0 {
 54→		return result, nil
 55→	}
 56→
 57→	providersUsedSet := make(map[string]bool)
 58→
 59→	// For each missing field, try providers in waterfall order
 60→	for _, field := range missingFields {
 61→		var providerNames []string
 62→		if len(req.Providers) > 0 {
 63→			// Use explicitly requested providers
 64→			providerNames = req.Providers
 65→		} else {
 66→			// Use default waterfall
 67→			providerNames = WaterfallForField(field)
 68→		}
 69→
 70→		filled := false
 71→		for _, provName := range providerNames {
 72→			provider, ok := registry.GetProvider(provName)
 73→			if !ok {
 74→				continue
 75→			}
 76→
 77→			// Check if this provider can fill this field
 78→			canFill := false
 79→			for _, pf := range provider.FieldsProvided {
 80→				if pf == field {
 81→					canFill = true
 82→					break
 83→				}
 84→			}
 85→			if !canFill {
 86→				continue
 87→			}
 88→
 89→			// Build cache key from provider + contact input
 90→			cacheInput := buildCacheInput(provider, contact)
 91→			cacheKey, err := assembly.CacheKey(provName, cacheInput)
 92→			if err != nil {
 93→				continue
 94→			}
 95→
 96→			// Check cache first
 97→			cached, err := assembly.GetCached(db, provName, cacheKey)
 98→			if err != nil {
 99→				log.Printf("cache lookup error for %s/%s: %v", provName, field, err)
100→				continue
101→			}
102→
103→			if cached != nil {
104→				// Extract field value from cached output
105→				var outputMap map[string]string
106→				if err := json.Unmarshal(cached.OutputData, &outputMap); err == nil {
107→					if val, ok := outputMap[field]; ok && val != "" {
108→						result.FieldsFilled[field] = val
109→						result.Cached++
110→						providersUsedSet[provName] = true
111→						filled = true
112→						break
113→					}
114→				}
115→			}
116→
117→			// Not cached -- this is where a real API call would go.
118→			// For now, log what WOULD happen and leave the field missing.
119→			log.Printf("enrich: would call provider %q (type=%s) to fill %q for %s",
120→				provName, provider.Type, field, req.ContactEmail)
121→			result.TotalCost += provider.CostPerCall
122→			providersUsedSet[provName] = true
123→		}
124→
125→		if !filled {
126→			result.FieldsMissing = append(result.FieldsMissing, field)
127→		}
128→	}
129→
130→	// Collect providers used
131→	for p := range providersUsedSet {
132→		result.ProvidersUsed = append(result.ProvidersUsed, p)
133→	}
134→
135→	// Update contacts table with any filled fields
136→	if len(result.FieldsFilled) > 0 {
137→		if err := updateContactFields(db, req.ContactEmail, result.FieldsFilled, result.ProvidersUsed); err != nil {
138→			return result, fmt.Errorf("updating contact: %w", err)
139→		}
140→	}
141→
142→	return result, nil
143→}
144→
145→// BatchEnrich finds unenriched contacts and enriches them.
146→func BatchEnrich(db *sql.DB, limit int) ([]EnrichResult, error) {
147→	rows, err := db.Query(`
148→		SELECT email FROM contacts
149→		WHERE enriched_at = '' OR enriched_at IS NULL
150→		ORDER BY created_at DESC
151→		LIMIT ?
152→	`, limit)
153→	if err != nil {
154→		return nil, fmt.Errorf("querying unenriched contacts: %w", err)
155→	}
156→	defer rows.Close()
157→
158→	var emails []string
159→	for rows.Next() {
160→		var email string
161→		if err := rows.Scan(&email); err != nil {
162→			continue
163→		}
164→		emails = append(emails, email)
165→	}
166→	if err := rows.Err(); err != nil {
167→		return nil, fmt.Errorf("scanning unenriched contacts: %w", err)
168→	}
169→
170→	var results []EnrichResult
171→	for _, email := range emails {
172→		r, err := Enrich(db, EnrichRequest{ContactEmail: email})
173→		if err != nil {
174→			log.Printf("enrich: skipping %s: %v", email, err)
175→			continue
176→		}
177→		results = append(results, *r)
178→	}
179→
180→	return results, nil
181→}
182→
183→// Stats returns enrichment coverage across all contacts.
184→func Stats(db *sql.DB) (*EnrichStats, error) {
185→	stats := &EnrichStats{
186→		FieldCoverage: make(map[string]int),
187→	}
188→
189→	// Total contacts
190→	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts`).Scan(&stats.TotalContacts); err != nil {
191→		return nil, fmt.Errorf("counting contacts: %w", err)
192→	}
193→
194→	// Enriched contacts (have enriched_at set)
195→	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts WHERE enriched_at != '' AND enriched_at IS NOT NULL`).Scan(&stats.Enriched); err != nil {
196→		return nil, fmt.Errorf("counting enriched contacts: %w", err)
197→	}
198→	stats.Unenriched = stats.TotalContacts - stats.Enriched
199→
200→	// Per-field coverage
201→	fieldColumns := map[string]string{
202→		"email":         "email",
203→		"name":          "name",
204→		"title":         "title",
205→		"company":       "company",
206→		"phone":         "phone",
207→		"industry":      "industry",
208→		"company_size":  "company_size",
209→		"funding_stage": "funding_stage",
210→		"website":       "website",
211→		"linkedin_url":  "linkedin_url",
212→	}
213→	for field, col := range fieldColumns {
214→		var count int
215→		query := fmt.Sprintf(`SELECT COUNT(*) FROM contacts WHERE %s != '' AND %s IS NOT NULL`, col, col)
216→		if err := db.QueryRow(query).Scan(&count); err != nil {
217→			continue
218→		}
219→		stats.FieldCoverage[field] = count
220→	}
221→
222→	return stats, nil
223→}
