249→// fieldMap returns current non-empty field values.
250→func (c *contactRow) fieldMap() map[string]string {
251→	return map[string]string{
252→		"email":         c.Email,
253→		"name":          c.Name,
254→		"title":         c.Title,
255→		"company":       c.Company,
256→		"phone":         c.Phone,
257→		"industry":      c.Industry,
258→		"company_size":  c.CompanySize,
259→		"funding_stage": c.FundingStage,
260→		"website":       c.Website,
261→		"linkedin_url":  c.LinkedInURL,
262→	}
