264→
265→// buildCacheInput constructs the input data for cache key generation
266→// based on the provider's input_type and the contact's available data.
267→func buildCacheInput(provider Provider, contact *contactRow) map[string]string {
268→	input := make(map[string]string)
269→	switch provider.InputType {
270→	case "email":
271→		input["email"] = contact.Email
272→	case "linkedin_url":
273→		input["linkedin_url"] = contact.LinkedInURL
274→	case "name_company":
275→		input["name"] = contact.Name
276→		input["company"] = contact.Company
277→	case "domain":
278→		input["domain"] = contact.Domain
279→	}
280→	return input
281→}
282→
283→// updateContactFields writes filled fields back to the contacts table
284→// and updates enriched_at and enrichment_sources.
285→func updateContactFields(db *sql.DB, email string, fields map[string]string, providers []string) error {
286→	var setClauses []string
287→	var args []any
288→
289→	for field, value := range fields {
290→		col, ok := enrichableColumns[field]
291→		if !ok {
292→			continue
293→		}
294→		setClauses = append(setClauses, fmt.Sprintf("%s = ?", col))
295→		args = append(args, value)
296→	}
297→
298→	if len(setClauses) == 0 {
299→		return nil
300→	}
301→
302→	// Update enriched_at
303→	setClauses = append(setClauses, "enriched_at = ?")
304→	args = append(args, time.Now().UTC().Format("2006-01-02 15:04:05"))
305→
306→	// Merge enrichment_sources
307→	sourcesJSON, _ := json.Marshal(providers)
308→	setClauses = append(setClauses, "enrichment_sources = ?")
309→	args = append(args, string(sourcesJSON))
310→
311→	// updated_at
312→	setClauses = append(setClauses, "updated_at = datetime('now')")
313→
314→	args = append(args, email)
315→
316→	query := fmt.Sprintf("UPDATE contacts SET %s WHERE email = ?", strings.Join(setClauses, ", "))
317→	_, err := db.Exec(query, args...)
318→	return err
319→}
